export { ExpandOnHover } from "./components/expand-on-hover/ExpandOnHover";
export { useExpand } from "./hooks/useExpand";
export type {
  ExpandItem,
  ExpandVariant,
  ExpandAnimationType,
  ExpandOnHoverProps,
  ExpandOnHoverRef,
} from "./types";
export { Preview } from "./components/expand-on-hover/Preview";
export { CardContent } from "./components/expand-on-hover/CardContent";
export { ExpandCard } from "./components/expand-on-hover/ExpandCard";

import { ReactNode } from "react";

export interface ExpandItem {
  id: string;
  title: string;
  subtitle?: string;
  image: string;
  description?: string;
  badge?: string;
  accent?: string; // e.g., custom hex, rgb, or styling class
}

export type ExpandVariant = "modern" | "minimal";
export type ExpandAnimationType = "spring" | "smooth";

export interface ExpandOnHoverProps {
  items: ExpandItem[];
  variant?: ExpandVariant;
  expandHeight?: number;
  collapsedHeight?: number;
  animation?: ExpandAnimationType;

  // Controlled & Uncontrolled states
  expandedId?: string | null;
  onExpandedChange?: (id: string | null) => void;
  defaultExpanded?: string | null;

  // Visuals and spacing
  gap?: number; // spacing in px
  borderRadius?: number; // border radius in px

  // Behaviors
  allowMultiple?: boolean; // if true, behaves like dynamic accordion
  hoverDelay?: number; // delay in ms before triggering expand
  clickToExpand?: boolean; // if true, ignore hovers and only expand on click/tap
  autoCollapseOnLeave?: boolean; // collapse all when cursor leaves component

  // Custom Render Prop
  renderItem?: (item: ExpandItem, isExpanded: boolean) => ReactNode;

  // Class overrides
  className?: string;
  cardClassName?: string;
}

export interface ExpandOnHoverRef {
  expand: (index: number) => void;
  collapse: () => void;
  next: () => void;
  prev: () => void;
}

import { useState, useRef, useCallback } from "react";
import { ExpandItem } from "../types";

interface UseExpandProps {
  items: ExpandItem[];
  expandedId?: string | null;
  onExpandedChange?: (id: string | null) => void;
  defaultExpanded?: string | null;
  hoverDelay?: number;
  clickToExpand?: boolean;
}

export function useExpand({
  expandedId: controlledId,
  onExpandedChange,
  defaultExpanded = null,
  hoverDelay = 50,
  clickToExpand = false,
}: UseExpandProps) {
  // Uncontrolled fallback state
  const [localExpandedId, setLocalExpandedId] = useState<string | null>(defaultExpanded);
  
  // Controlled vs Uncontrolled determination
  const isControlled = controlledId !== undefined;
  const activeId = isControlled ? controlledId : localExpandedId;

  const hoverTimeoutRef = useRef<NodeJS.Timeout | null>(null);

  const setExpanded = useCallback(
    (id: string | null) => {
      if (isControlled) {
        onExpandedChange?.(id);
      } else {
        setLocalExpandedId(id);
      }
    },
    [isControlled, onExpandedChange]
  );

  const clearHoverTimeout = useCallback(() => {
    if (hoverTimeoutRef.current) {
      clearTimeout(hoverTimeoutRef.current);
      hoverTimeoutRef.current = null;
    }
  }, []);

  const handleHoverStart = useCallback(
    (id: string) => {
      if (clickToExpand) return;
      clearHoverTimeout();
      
      if (hoverDelay > 0) {
        hoverTimeoutRef.current = setTimeout(() => {
          setExpanded(id);
        }, hoverDelay);
      } else {
        setExpanded(id);
      }
    },
    [clickToExpand, hoverDelay, setExpanded, clearHoverTimeout]
  );

  const handleHoverEnd = useCallback(() => {
    if (clickToExpand) return;
    clearHoverTimeout();
  }, [clickToExpand, clearHoverTimeout]);

  const handleCardClick = useCallback(
    (id: string) => {
      // Click/Tap toggle: if already expanded, collapse it; otherwise expand it.
      if (activeId === id) {
        setExpanded(null);
      } else {
        setExpanded(id);
      }
    },
    [activeId, setExpanded]
  );

  return {
    activeId,
    setExpanded,
    handleHoverStart,
    handleHoverEnd,
    handleCardClick,
    clearHoverTimeout,
  };
}

import React, { forwardRef, useImperativeHandle, useId } from "react";
import { LayoutGroup, motion } from "framer-motion";
import { ExpandOnHoverProps, ExpandOnHoverRef } from "../../types";
import { useExpand } from "../../hooks/useExpand";
import { ExpandCard } from "./ExpandCard";
import { cn } from "../../../../lib/utils";

export const ExpandOnHover = forwardRef<ExpandOnHoverRef, ExpandOnHoverProps>(
  (
    {
      items,
      variant = "modern",
      expandHeight = 420,
      collapsedHeight = 52,
      animation = "spring",
      expandedId,
      onExpandedChange,
      defaultExpanded = null,
      gap = 12,
      borderRadius = 24,
      hoverDelay = 50,
      clickToExpand = false,
      autoCollapseOnLeave = true,
      renderItem,
      className,
      cardClassName,
    },
    ref
  ) => {
    // Generate unique LayoutGroup ID to prevent cross-component interference
    const layoutGroupId = useId();

    const {
      activeId,
      setExpanded,
      handleHoverStart,
      handleHoverEnd,
      handleCardClick,
    } = useExpand({
      items,
      expandedId,
      onExpandedChange,
      defaultExpanded,
      hoverDelay,
      clickToExpand,
    });

    // Find the numerical index of the currently active/expanded card
    const activeIndex = items.findIndex((item) => item.id === activeId);
    const resolvedActiveIndex = activeIndex === -1 ? null : activeIndex;

    // Expose Imperative API methods via forwardRef
    useImperativeHandle(ref, () => ({
      expand: (index: number) => {
        if (index >= 0 && index < items.length) {
          setExpanded(items[index].id);
        }
      },
      collapse: () => {
        setExpanded(null);
      },
      next: () => {
        const nextIndex = activeIndex === -1 ? 0 : (activeIndex + 1) % items.length;
        setExpanded(items[nextIndex].id);
      },
      prev: () => {
        const prevIndex =
          activeIndex === -1
            ? items.length - 1
            : (activeIndex - 1 + items.length) % items.length;
        setExpanded(items[prevIndex].id);
      },
    }));

    // Keyboard controls for Arrow keys + Escape + Space/Enter
    const handleKeyDown = (e: React.KeyboardEvent, index: number) => {
      const targetItem = items[index];
      
      switch (e.key) {
        case "ArrowDown":
          e.preventDefault();
          const nextCard = document.getElementById(`card-${layoutGroupId}-${index + 1}`);
          nextCard?.focus();
          break;
        case "ArrowUp":
          e.preventDefault();
          const prevCard = document.getElementById(`card-${layoutGroupId}-${index - 1}`);
          prevCard?.focus();
          break;
        case "Escape":
          e.preventDefault();
          setExpanded(null);
          break;
        case "Enter":
        case " ":
          e.preventDefault();
          handleCardClick(targetItem.id);
          break;
        default:
          break;
      }
    };

    // Auto-collapse when cursor fully exits the component area
    const handleMouseLeaveContainer = () => {
      if (autoCollapseOnLeave && !clickToExpand) {
        setExpanded(null);
      }
    };

    return (
      <LayoutGroup id={layoutGroupId}>
        <motion.div
          layout
          onMouseLeave={handleMouseLeaveContainer}
          style={{ gap: `${gap}px` }}
          className={cn("flex flex-col w-full max-w-xl mx-auto", className)}
        >
          {items.map((item, index) => {
            const isExpanded = activeId === item.id;
            
            return (
              <ExpandCard
                key={item.id}
                item={item}
                index={index}
                activeIndex={resolvedActiveIndex}
                isExpanded={isExpanded}
                expandHeight={expandHeight}
                collapsedHeight={collapsedHeight}
                variant={variant}
                animation={animation}
                borderRadius={borderRadius}
                clickToExpand={clickToExpand}
                onHoverStart={() => handleHoverStart(item.id)}
                onHoverEnd={handleHoverEnd}
                onClick={() => handleCardClick(item.id)}
                onKeyDown={(e) => handleKeyDown(e, index)}
                renderItem={renderItem}
                cardClassName={cardClassName}
                // Overriding ID with layoutGroupId prefix to prevent focus collision when rendering multiple lists
                {...{ id: `card-${layoutGroupId}-${index}` }}
              />
            );
          })}
        </motion.div>
      </LayoutGroup>
    );
  }
);

ExpandOnHover.displayName = "ExpandOnHover";

import { motion } from "framer-motion";
import { ExpandItem } from "../../types";

interface PreviewProps {
  item: ExpandItem;
  index: number;
}

export function Preview({ item, index }: PreviewProps) {
  return (
    <motion.div
      layout="position"
      className="flex items-center justify-between w-full h-full px-6 select-none"
    >
      <div className="flex items-center gap-4">
        {/* Index counter */}
        <span className="text-xs font-mono font-bold opacity-40 text-neutral-400">
          {(index + 1).toString().padStart(2, "0")}
        </span>
        
        {/* Title */}
        <span className="font-sans text-sm font-bold tracking-tight text-white">
          {item.title}
        </span>
      </div>

      <div className="flex items-center gap-3">
        {/* Optional Badge */}
        {item.badge && (
          <span className="px-2.5 py-0.5 rounded-full text-[9px] font-mono font-bold tracking-wider bg-white/10 text-white/90 border border-white/10 backdrop-blur-sm">
            {item.badge}
          </span>
        )}
        
        {/* Minimal accent dot */}
        <div
          className="w-1.5 h-1.5 rounded-full shadow-[0_0_8px_var(--accent-glow)]"
          style={{ 
            backgroundColor: item.accent || "#ffffff",
            // @ts-ignore
            "--accent-glow": item.accent || "#ffffff"
          }}
        />
      </div>
    </motion.div>
  );
}

import { motion } from "framer-motion";
import { ExpandItem } from "../../types";

interface CardContentProps {
  item: ExpandItem;
  imageParallaxStyle?: any; // Dynamics for pointer parallax shifts
  index: number;
  borderRadius?: number;
}

export function CardContent({ item, imageParallaxStyle, index, borderRadius = 24 }: CardContentProps) {
  // Stagger variants for content reveals
  const revealContainer = {
    hidden: { opacity: 0 },
    visible: {
      opacity: 1,
      transition: {
        staggerChildren: 0.05,
        delayChildren: 0.12,
      },
    },
  };

  const revealChild = {
    hidden: { opacity: 0, y: 16, filter: "blur(4px)" },
    visible: {
      opacity: 1,
      y: 0,
      filter: "blur(0px)",
      transition: {
        type: "spring",
        stiffness: 140,
        damping: 18,
      },
    },
  };

  const clipStyle = {
    borderRadius: `${borderRadius}px`,
    clipPath: `inset(0px round ${borderRadius}px)`,
    WebkitClipPath: `inset(0px round ${borderRadius}px)`,
  };

  return (
    <div className="relative w-full h-full overflow-hidden rounded-[inherit] select-none" style={clipStyle}>
      {/* Background Grayscale Image */}
      <div className="absolute inset-0 w-full h-full bg-neutral-950 overflow-hidden rounded-[inherit]" style={clipStyle}>
        <motion.img
          src={item.image}
          alt={item.title}
          loading="lazy"
          style={{ ...imageParallaxStyle, ...clipStyle }}
          className="absolute inset-0 w-full h-full object-cover brightness-75 contrast-105 rounded-[inherit]"
          initial={{ opacity: 0, scale: 0.95, filter: "blur(8px)" }}
          animate={{ opacity: 1, scale: 1, filter: "blur(0px)" }}
          exit={{ opacity: 0, scale: 0.95, filter: "blur(8px)" }}
          transition={{ duration: 0.6, ease: [0.16, 1, 0.3, 1] }}
        />
        {/* Soft Linear Gradient Overlay */}
        <div className="absolute inset-0 bg-gradient-to-t from-neutral-950 via-neutral-950/50 to-transparent rounded-[inherit]" style={clipStyle} />
      </div>

      {/* Dynamic Staggered Panels */}
      <motion.div
        variants={revealContainer}
        initial="hidden"
        animate="visible"
        className="absolute inset-0 flex flex-col justify-end p-8 text-left z-10"
      >
        <div className="space-y-4">
          {/* Header Category/Badge */}
          {item.badge && (
            <motion.div variants={revealChild}>
              <span className="inline-block px-3 py-1 rounded-full text-[9px] font-mono font-bold tracking-widest bg-white/10 text-white border border-white/20 backdrop-blur-md">
                {item.badge}
              </span>
            </motion.div>
          )}

          {/* Title and Subtitle Block */}
          <div className="space-y-1">
            {item.subtitle && (
              <motion.p
                variants={revealChild}
                className="text-xs font-mono font-semibold tracking-wider text-neutral-400"
              >
                {item.subtitle}
              </motion.p>
            )}
            
            <motion.h3
              variants={revealChild}
              className="font-sans text-2xl md:text-3xl font-black tracking-tight text-white"
            >
              {item.title}
            </motion.h3>
          </div>

          {/* Description Block */}
          {item.description && (
            <motion.p
              variants={revealChild}
              className="font-sans text-sm leading-relaxed text-neutral-300 max-w-md line-clamp-3"
            >
              {item.description}
            </motion.p>
          )}

          {/* Interactive Indicators */}
          <motion.div
            variants={revealChild}
            className="flex items-center gap-4 pt-2"
          >
            <div className="flex items-center gap-1.5 text-[10px] font-mono font-bold text-white tracking-widest hover:opacity-80 transition-opacity cursor-pointer">
              <span>Explore</span>
              <svg 
                className="w-3.5 h-3.5 fill-none stroke-current stroke-2 transition-transform duration-300 group-hover:translate-x-1" 
                viewBox="0 0 24 24"
              >
                <path strokeLinecap="round" strokeLinejoin="round" d="M13.5 4.5L21 12m0 0l-7.5 7.5M21 12H3" />
              </svg>
            </div>
            
            <span className="text-neutral-700 font-mono text-xs">/</span>
            
            <span className="text-[9px] font-mono font-bold text-neutral-500 tracking-widest select-none">
              Index {(index + 1).toString().padStart(2, "0")}
            </span>
          </motion.div>
        </div>
      </motion.div>
    </div>
  );
}

import React, { useRef } from "react";
import { motion, useMotionValue, useSpring } from "framer-motion";
import { ExpandItem, ExpandVariant, ExpandAnimationType } from "../../types";
import { Preview } from "./Preview";
import { CardContent } from "./CardContent";
import { cn } from "../../../../lib/utils";

interface ExpandCardProps {
  item: ExpandItem;
  index: number;
  activeIndex: number | null;
  isExpanded: boolean;
  expandHeight: number;
  collapsedHeight: number;
  variant: ExpandVariant;
  animation: ExpandAnimationType;
  borderRadius: number;
  clickToExpand: boolean;
  onHoverStart: () => void;
  onHoverEnd: () => void;
  onClick: () => void;
  onKeyDown: (e: React.KeyboardEvent<HTMLDivElement>) => void;
  renderItem?: (item: ExpandItem, isExpanded: boolean) => React.ReactNode;
  cardClassName?: string;
}

export function ExpandCard({
  item,
  index,
  activeIndex,
  isExpanded,
  expandHeight,
  collapsedHeight,
  variant,
  animation,
  borderRadius,
  clickToExpand,
  onHoverStart,
  onHoverEnd,
  onClick,
  onKeyDown,
  renderItem,
  cardClassName,
}: ExpandCardProps) {
  const cardRef = useRef<HTMLDivElement>(null);

  // Motion Values for tilt and image parallax
  const rotateXValue = useMotionValue(0);
  const rotateYValue = useMotionValue(0);
  const imageXValue = useMotionValue(0);
  const imageYValue = useMotionValue(0);

  // Easing/Spring configurations
  const springSettings = { stiffness: 170, damping: 22, mass: 0.8 };
  const smoothSettings = { type: "tween", ease: [0.16, 1, 0.3, 1], duration: 0.6 };
  const transitionConfig = animation === "spring" ? springSettings : smoothSettings;

  // React springs for lag-free cursor tracking
  const rotateX = useSpring(rotateXValue, { stiffness: 220, damping: 25 });
  const rotateY = useSpring(rotateYValue, { stiffness: 220, damping: 25 });
  const imageX = useSpring(imageXValue, { stiffness: 220, damping: 25 });
  const imageY = useSpring(imageYValue, { stiffness: 220, damping: 25 });

  // Handle cursor movement inside card to execute 3D tilt and image shift
  const handleMouseMove = (e: React.MouseEvent<HTMLDivElement>) => {
    if (!isExpanded || clickToExpand || !cardRef.current) return;
    const rect = cardRef.current.getBoundingClientRect();

    // Relative coordinates (-0.5 to 0.5)
    const relativeX = (e.clientX - rect.left) / rect.width - 0.5;
    const relativeY = (e.clientY - rect.top) / rect.height - 0.5;

    // Subtle 3D tilt (max 3 degrees)
    rotateXValue.set(relativeY * -3);
    rotateYValue.set(relativeX * 3);

    // Subtle image parallax shift (max 8px)
    imageXValue.set(relativeX * 8);
    imageYValue.set(relativeY * 8);
  };

  const handleMouseLeave = () => {
    // Reset positions smoothly
    rotateXValue.set(0);
    rotateYValue.set(0);
    imageXValue.set(0);
    imageYValue.set(0);
    onHoverEnd();
  };

  // Sibling layout displacement (parting effect)
  let partingY = 0;
  let scale = 1;
  let opacity = 1;

  if (activeIndex !== null) {
    if (activeIndex === index) {
      partingY = 0;
      scale = 1;
      opacity = 1;
    } else {
      scale = 0.98;
      opacity = 0.65;
      // Cards above shift up (-12px), cards below shift down (+12px)
      partingY = index < activeIndex ? -12 : 12;
    }
  }

  // Variant classes
  const isModern = variant === "modern";
  const variantClasses = isModern
    ? cn(
        "bg-neutral-900/40 border border-white/10 backdrop-blur-md",
        isExpanded 
          ? "shadow-[0_25px_60px_-15px_rgba(0,0,0,0.8),0_0_40px_rgba(255,255,255,0.05)] border-white/20" 
          : "shadow-md hover:border-white/20 hover:bg-neutral-900/60"
      )
    : "bg-neutral-950 border border-neutral-800 shadow-none";

  return (
    <motion.div
      ref={cardRef}
      role="button"
      tabIndex={0}
      aria-expanded={isExpanded}
      aria-controls={`panel-${item.id}`}
      id={`card-${index}`}
      layout
      transition={transitionConfig}
      onMouseEnter={onHoverStart}
      onMouseLeave={handleMouseLeave}
      onMouseMove={handleMouseMove}
      onClick={onClick}
      onKeyDown={onKeyDown}
      animate={{
        y: partingY,
        scale,
        opacity,
      }}
      style={{
        height: isExpanded ? expandHeight : collapsedHeight,
        borderRadius: `${borderRadius}px`,
        clipPath: `inset(0px round ${borderRadius}px)`,
        WebkitClipPath: `inset(0px round ${borderRadius}px)`,
        rotateX,
        rotateY,
        perspective: 1000,
      }}
      className={cn(
        "relative w-full overflow-hidden cursor-pointer select-none outline-none transition-all duration-300 rounded-[inherit]",
        "focus-visible:ring-2 focus-visible:ring-white/80 focus-visible:ring-offset-4 focus-visible:ring-offset-neutral-950",
        variantClasses,
        cardClassName
      )}
    >
      {renderItem ? (
        renderItem(item, isExpanded)
      ) : (
        <div 
          className="relative w-full h-full rounded-[inherit] overflow-hidden"
          style={{
            clipPath: `inset(0px round ${borderRadius}px)`,
            WebkitClipPath: `inset(0px round ${borderRadius}px)`,
          }}
        >
          {/* Collapsed Preview container */}
          <motion.div
            layout="position"
            animate={{ 
              opacity: isExpanded ? 0 : 1,
              pointerEvents: isExpanded ? "none" : "auto" 
            }}
            transition={{ duration: 0.2 }}
            className="absolute inset-0 w-full h-full flex items-center rounded-[inherit] overflow-hidden"
          >
            <Preview item={item} index={index} />
          </motion.div>

          {/* Expanded Content Panel container */}
          <motion.div
            layout="position"
            animate={{ 
              opacity: isExpanded ? 1 : 0,
              pointerEvents: isExpanded ? "auto" : "none" 
            }}
            transition={{ duration: 0.3 }}
            className="absolute inset-0 w-full h-full rounded-[inherit] overflow-hidden"
          >
            {isExpanded && (
              <CardContent 
                item={item} 
                index={index} 
                borderRadius={borderRadius}
                imageParallaxStyle={{ x: imageX, y: imageY }} 
              />
            )}
          </motion.div>
        </div>
      )}
    </motion.div>
  );
}
